use std::{borrow::Cow, path::Path};

use specta::TypeCollection;
use specta_serde::SerdeMode;

use crate::{error::Result, primitives::export_type};

/// ReScript language exporter.
#[derive(Debug, Clone)]
pub struct ReScript {
    /// Header comment placed at the top of the generated file.
    pub header: Cow<'static, str>,
    /// Serde mode for type transformations. `None` disables serde processing.
    pub serde: Option<SerdeMode>,
}

impl Default for ReScript {
    fn default() -> Self {
        Self {
            header: "// This file has been generated by Specta. DO NOT EDIT.".into(),
            serde: Some(SerdeMode::Both),
        }
    }
}

impl ReScript {
    /// Create a new ReScript exporter with default configuration.
    pub fn new() -> Self {
        Self::default()
    }

    /// Set the header comment for the generated file.
    pub fn header(mut self, header: impl Into<Cow<'static, str>>) -> Self {
        self.header = header.into();
        self
    }

    /// Enable Serde transformation with the given mode.
    pub fn with_serde(mut self, mode: SerdeMode) -> Self {
        self.serde = Some(mode);
        self
    }

    /// Configure the exporter to export the types for `#[derive(serde::Serialize)]`
    pub fn with_serde_serialize(self) -> Self {
        self.with_serde(SerdeMode::Serialize)
    }

    /// Configure the exporter to export the types for `#[derive(serde::Deserialize)]`
    pub fn with_serde_deserialize(self) -> Self {
        self.with_serde(SerdeMode::Deserialize)
    }

    /// Disable Serde transformation.
    pub fn without_serde(mut self) -> Self {
        self.serde = None;
        self
    }

    /// Export all types in the collection to a ReScript string.
    pub fn export(&self, types: &TypeCollection) -> Result<String> {
        let mut processed = types.clone();
        if let Some(mode) = self.serde {
            specta_serde::apply(&mut processed, mode)?;
        }

        let mut out = String::new();

        if !self.header.is_empty() {
            out.push_str(&self.header);
            out.push('\n');
        }

        let sorted = processed.into_topological_iter()?;

        for ndt in sorted {
            let rendered = export_type(&processed, ndt)?;
            if !rendered.is_empty() {
                out.push('\n');
                out.push_str(&rendered);
            }
        }

        Ok(out)
    }

    /// Export all types to a `.res` file.
    pub fn export_to(&self, path: impl AsRef<Path>, types: &TypeCollection) -> Result<()> {
        let content = self.export(types)?;
        if let Some(parent) = path.as_ref().parent() {
            std::fs::create_dir_all(parent)?;
        }
        std::fs::write(path, content)?;
        Ok(())
    }
}
